const response = $input.first().json;
const text = response.choices?.[0]?.message?.content ?? '';

let translations = {};
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    translations = JSON.parse(jsonMatch[0]);
  } else {
    translations = JSON.parse(text);
  }
} catch (e) {
  throw new Error('OpenAI-Antwort konnte nicht geparst werden: ' + text.slice(0, 200));
}

const productId = $('Produkt-Daten extrahieren').first().json.id;
const productName = $('Produkt-Daten extrahieren').first().json.de?.name ?? productId;

return [{ json: { productId, productName, translations } }];

